"use strict";

var plots = plots ?? {};
plots.axisPanZoom = plots.axisPanZoom ?? {};

plots.axisPanZoom.state = {};

plots.axisPanZoom.svgNS = "http://www.w3.org/2000/svg";

plots.axisPanZoom.parseOr = (str, y) => {
  if ((str ?? null) === null) return y;
  const x = Number(str);
  return Number.isFinite(x) ? x : y;
};

plots.axisPanZoom.getBBoxCenter = e => {
  const box = e.getBBox();
  return [box.x + box.width * .5, box.y + box.height * .5];
};

plots.axisPanZoom.setTransform = (e, tx, ty, sx, sy) => {
  const {svgNS, getBBoxCenter} = plots.axisPanZoom;

  const svg = e.ownerSVGElement;
  if (!svg) throw new Error("Element is not in an <svg> tree.");

  const transform = (e, tx, ty, sx, sy) => {
    const xf = e.transform.baseVal;
    xf.clear();

    const t = svg.createSVGTransform();
    t.setTranslate(tx, ty);

    const s = svg.createSVGTransform();
    s.setScale(sx, sy);

    xf.appendItem(s);
    xf.appendItem(t);
  };

  const backScale = (e, sxInv, syInv) => {
    const xf = e.transform.baseVal;
    xf.clear();

    const [cx, cy] = getBBoxCenter(e);

    const t1 = svg.createSVGTransform();
    t1.setTranslate(cx, cy);

    const s = svg.createSVGTransform();
    s.setScale(sxInv, syInv);

    const t2 = svg.createSVGTransform();
    t2.setTranslate(-cx, -cy);

    xf.appendItem(t1);
    xf.appendItem(s);
    xf.appendItem(t2);
  };

  let eToTransform = e;
  if (e.classList.contains("axis-pan-zoom-no-clip-path")) {
    // All good
  } else if (e.classList.contains("axis-pan-zoom-clip-path")) {
    eToTransform = e.firstElementChild;
  } else {
    if (e.hasAttribute("clip-path")) {
      e.classList.add("axis-pan-zoom-clip-path");
      const g = document.createElementNS(svgNS, "g");
      while (e.firstChild) g.appendChild(e.firstChild);
      e.appendChild(g);
      eToTransform = g;
    } else {
      e.classList.add("axis-pan-zoom-no-clip-path");
    }
  }

  if (!("axisPanZoomUsesList" in e.dataset)) {
    const uses = e.querySelectorAll("use");
    const hrefs = new Set();
    for (const use of uses) hrefs.add(use.href.baseVal ?? use.href);
    e.dataset.axisPanZoomUsesList = JSON.stringify(Array.from(hrefs));
  }

  const hrefs = JSON.parse(e.dataset.axisPanZoomUsesList);
  let templates = hrefs.map(href => document.getElementById(
    href.slice(href.lastIndexOf("#") + 1)));

  if (!e.classList.contains("axis-pan-zoom-vector-effects")) {
    const selector = "line, rect, path";
    const es = new Set(e.querySelectorAll(selector));
    for (const e of templates) {
      if (e.matches(selector)) es.add(e);
      for (const x of e.querySelectorAll(selector)) es.add(x);
    }
    for (const e of es) e.setAttribute("vector-effect", "non-scaling-stroke");
    e.classList.add("axis-pan-zoom-vector-effects");
  }

  transform(eToTransform, tx, ty, sx, sy);

  { // Backscaling
    const [sxInv, syInv] = [1 / sx, 1 / sy];
    const es = e.querySelectorAll("circle, ellipse, text");

    if (!e.classList.contains("axis-pan-zoom-backscale-wrap")) {
      for (const e of es) {
        const parent = e.parentElement;
        const g = document.createElementNS(svgNS, "g");
        parent.insertBefore(g, e)
        g.appendChild(e);
      }
      e.classList.add("axis-pan-zoom-backscale-wrap");
    }

    for (const e of es) backScale(e.parentElement, sxInv, syInv);

    for (const e of templates) {
      if (e.localName === "ellipse") {
        const rxOrig = e.dataset.axisPanZoomOriginalRx ??= e.rx.baseVal.value;
        const ryOrig = e.dataset.axisPanZoomOriginalRy ??= e.ry.baseVal.value;
        e.setAttribute("rx", rxOrig * sxInv);
        e.setAttribute("ry", ryOrig * syInv);
      }
    }
  }
};

