plots.axisPanZoom.applyTransform = (axisContainer) => {
  const {setTransform, parseOr, getBBoxCenter} = plots.axisPanZoom;

  const xAxisOffset = parseOr(axisContainer.dataset.xAxisOffset, 0);
  const yAxisOffset = parseOr(axisContainer.dataset.yAxisOffset, 0);
  const xAxisScale = parseOr(axisContainer.dataset.xAxisScale, 1);
  const yAxisScale = parseOr(axisContainer.dataset.yAxisScale, 1);

  for (const child of axisContainer.children) {
    if (child.classList.contains("grid") ||
        child.classList.contains("content")) {
      setTransform(child, xAxisOffset, yAxisOffset, xAxisScale, yAxisScale);
    } else if (child.classList.contains("frame")) {
      for (const [k, args, i] of [
          ["x", [xAxisOffset, 0, xAxisScale, 1], 0],
          ["y", [0, yAxisOffset, 1, yAxisScale], 1]]) {
        const es = child.querySelectorAll(
          `.span.${k}-axis g.tick.major, .span.${k}-axis g.tick.minor`);
        for (const e of es) {
          const span = e.parentElement;
          if (!span.hasAttribute("data-axis-pan-zoom-span-min")) {
            const line = span.querySelector(":scope > line");
            const box = (line ?? span).getBBox();
            if (k === "x") {
              span.dataset.axisPanZoomSpanMin = box.x;
              span.dataset.axisPanZoomSpanMax = box.x + box.width;
            } else {
              span.dataset.axisPanZoomSpanMin = box.y;
              span.dataset.axisPanZoomSpanMax = box.y + box.height;
            }
          }

          setTransform(e, ...args);

          const min = Number(span.dataset.axisPanZoomSpanMin);
          const max = Number(span.dataset.axisPanZoomSpanMax);
          const offset = args[i];
          const scale = args[i + 2];

          for (const tick of e.children) {
            tick.classList.remove("axis-pan-zoom-hide");
            const c = (getBBoxCenter(tick)[i] + offset) * scale;
            if (c < min || c > max) tick.classList.add("axis-pan-zoom-hide");
          }
        }
      }
    }
  }
};

plots.axisPanZoom.applyTransforms = (axisContainer) => {
  const {state, parseOr, applyTransform} = plots.axisPanZoom;
  const {xAxes, yAxes} = state;
  const [xAxis, yAxis] = [
    axisContainer.dataset.xAxisId ?? null,
    axisContainer.dataset.yAxisId ?? null];
  const parsedDataset = {
    xAxisOffset: parseOr(axisContainer.dataset.xAxisOffset, null),
    yAxisOffset: parseOr(axisContainer.dataset.yAxisOffset, null),
    xAxisScale: parseOr(axisContainer.dataset.xAxisScale, null),
    yAxisScale: parseOr(axisContainer.dataset.yAxisScale, null)}

  const xAxisContainers = xAxes[xAxis] ?? new Set();
  const yAxisContainers = yAxes[yAxis] ?? new Set();

  for (const [k1, axisContainers] of [
      ["x", xAxisContainers], ["y", yAxisContainers]]) {
    for (const axisContainer of axisContainers) {
      for (const k2 of ["Offset", "Scale"]) {
        const k = k1 + "Axis" + k2;
        const parsed = parsedDataset[k];
        if (parsed === null) {
          delete axisContainer.dataset[k];
        } else {
          axisContainer.dataset[k] = parsed;
        }
      }
    }
  }

  const axisContainers = xAxisContainers.union(yAxisContainers);
  for (const axisContainer of axisContainers) applyTransform(axisContainer);
};

plots.axisPanZoom.resetInteractionState = () => {
  const {state} = plots.axisPanZoom;
  [state.xAxis, state.yAxis] = [null, null];
  [state.xAnchor, state.yAnchor] = [null, null];
  [state.xAnchorTr, state.yAnchorTr] = [null, null];
  [state.xPointer, state.yPointer] = [null, null];
  state.zoom = null;
};

plots.axisPanZoom.clientToSvgLocalXy = (x, y) => {
  if ((x ?? null) === null || (y ?? null) === null) return [null, null];
  const point = new DOMPoint(x, y);
  const ctm = document.documentElement.getScreenCTM();
  if (!ctm) return [null, null];
  const pointTr = point.matrixTransform(ctm.inverse());
  return [pointTr.x, pointTr.y];
};

plots.axisPanZoom.onPointerDown = event => {
  // Make sure other clickable targets are not intercepted
  if (event.target.closest?.(".clickable")) return;

  const {state, parseOr, clientToSvgLocalXy} = plots.axisPanZoom;
  const axisContainer = event.currentTarget;
  [state.xAxis, state.yAxis] = [
    axisContainer.dataset.xAxisId ?? null,
    axisContainer.dataset.yAxisId ?? null];
  const [xOffset, yOffset] = [
    parseOr(axisContainer.dataset.xAxisOffset, 0),
    parseOr(axisContainer.dataset.yAxisOffset, 0)];
  const [xScale, yScale] = [
    parseOr(axisContainer.dataset.xAxisScale, 1),
    parseOr(axisContainer.dataset.yAxisScale, 1)];
  [state.xAnchor, state.yAnchor] =
    clientToSvgLocalXy(event.clientX, event.clientY);
  [state.xAnchorTr, state.yAnchorTr] = [
      [state.xAnchor, xOffset, xScale],
      [state.yAnchor, yOffset, yScale]].map(([z, offset, scale]) => {
    if (z === null) return null;
    return z / scale - offset;
  });
  [state.xPointer, state.yPointer] = [state.xAnchor, state.yAnchor];
  state.zoom = {0: false, 2: true}[event.button] ?? null;
  if (state.zoom !== null) axisContainer.setPointerCapture(event.pointerId);
};

plots.axisPanZoom.onPointerMove = event => {
  event.preventDefault();
  const {state, parseOr, applyTransforms, clientToSvgLocalXy} =
    plots.axisPanZoom;
  const {xAnchor, yAnchor, xAnchorTr, yAnchorTr, xPointer, yPointer, zoom} =
    state;
  const axisContainer = event.currentTarget;

  const [xPointerNext, yPointerNext] =
    clientToSvgLocalXy(event.clientX, event.clientY);

  const [xOffset, yOffset] = [
    parseOr(axisContainer.dataset.xAxisOffset, 0),
    parseOr(axisContainer.dataset.yAxisOffset, 0)];
  const [xScale, yScale] = [
    parseOr(axisContainer.dataset.xAxisScale, 1),
    parseOr(axisContainer.dataset.yAxisScale, 1)];

  for (const [anchor, anchorTr, pointer, pointerNext, offset, scale, k] of [
      [xAnchor, xAnchorTr, xPointer, xPointerNext, xOffset, xScale, "x"],
      [yAnchor, yAnchorTr, yPointer, yPointerNext, yOffset, yScale, "y"]]) {
    let isOkay = true;
    for (const x of [anchor, anchorTr, pointer, pointerNext, offset, scale])
      if ((x ?? null) === null) { isOkay = false; break; }
    if (!isOkay) continue;

    const pointerDelta = pointerNext - pointer;

    if (zoom === false) {
      const sensitivity = 1 / scale;
      axisContainer.dataset[k + "AxisOffset"] =
        offset + (pointerDelta * sensitivity);
    } else if (zoom === true) {
      const sensitivity = .01 * (k === "x" ? 1 : -1);
      const scaleNext = scale * 2 ** (pointerDelta * sensitivity);
      axisContainer.dataset[k + "AxisScale"] = scaleNext;
      axisContainer.dataset[k + "AxisOffset"] = anchor / scaleNext - anchorTr;
    }
  }

  [state.xPointer, state.yPointer] = [xPointerNext, yPointerNext];

  if ((zoom ?? null) !== null) applyTransforms(axisContainer);
};

plots.axisPanZoom.endInteraction = event => {
  plots.axisPanZoom.resetInteractionState();
  if (event) {
    const axisContainer = event.currentTarget;
    if ((event.pointerId ?? null) !== null)
      axisContainer.releasePointerCapture(event.pointerId);
  }
};

plots.axisPanZoom.onDblClick = event => {
  event.preventDefault();
  const axisContainer = event.currentTarget;

  delete axisContainer.dataset.xAxisOffset;
  delete axisContainer.dataset.yAxisOffset;
  delete axisContainer.dataset.xAxisScale;
  delete axisContainer.dataset.yAxisScale;

  plots.axisPanZoom.applyTransforms(axisContainer);
};

plots.axisPanZoom.onContextMenu = event => {
  event.preventDefault();
};

plots.axisPanZoom.init = () => {
  const {state, svgNS} = plots.axisPanZoom;
  const {resetInteractionState, onPointerDown, onPointerMove, endInteraction,
    onDblClick, onContextMenu} = plots.axisPanZoom;

  resetInteractionState();

  // state.clipPathCounter = 0;

  [state.xAxes, state.yAxes] = [{}, {}];
  const axisContainers = document.querySelectorAll(
    "[data-x-axis-id], [data-y-axis-id]");
  for (const axisContainer of axisContainers) {
    const {xAxisId, yAxisId} = axisContainer.dataset;
    for (const [axes, axisId] of [
        [state.xAxes, xAxisId], [state.yAxes, yAxisId]]) {
      if (axisId) {
        axes[axisId] = axes[axisId] ?? new Set();
        axes[axisId].add(axisContainer);
      }
    }

    const box = axisContainer.getBBox();
    const rect = document.createElementNS(svgNS, "rect");
    rect.setAttribute("x", box.x);
    rect.setAttribute("y", box.y);
    rect.setAttribute("width", box.width);
    rect.setAttribute("height", box.height);
    rect.style.fill = "transparent";
    rect.style.stroke = "none";
    rect.style.pointerEvents = "all";
    axisContainer.insertBefore(rect, axisContainer.firstChild);

    axisContainer.addEventListener("pointerdown", onPointerDown);
    axisContainer.addEventListener("pointermove", onPointerMove);
    axisContainer.addEventListener("pointerup", endInteraction);
    axisContainer.addEventListener("pointercancel", endInteraction);
    axisContainer.addEventListener("lostpointercapture", endInteraction);
    axisContainer.addEventListener("dblclick", onDblClick);
    axisContainer.addEventListener("contextmenu", onContextMenu);
  }

  const style = document.createElementNS(svgNS, "style");
  style.textContent = ".axis-pan-zoom-hide { display: none; }";
  document.documentElement.insertBefore(style,
    document.documentElement.firstChild);

  if (!document.querySelector(":scope > defs")) {
    const defs = document.createElementNS(svgNS, "defs");
    document.documentElement.insertBefore(defs,
      document.documentElement.firstChild);
  }
}

document.addEventListener("DOMContentLoaded", () => {
  plots.axisPanZoom.init();
});


"use strict";

var plots = plots ?? {};
plots.toggles = plots.toggles ?? {};

// ---------- configuration (tweak here) ----------
plots.toggles.classes = plots.toggles.classes ?? {
  toggles: "toggles",
  panel: "panel",
  hidden: "hide",
  bg: "frame",
  title: "pt-title",
  treeViewport: "pt-tree-viewport",
  treeContent: "pt-tree-content",
  row: "entry",
  rowHit: "entry-hit",
  label: "label",
  cbBox: "checkbox-box",
  cbMark: "checkbox-mark",
  clickable: "clickable"
};

plots.toggles.defaults = {
  title: "Layers",
  hotkey: "/",
  includeRoot: true,
  useForeignObject: false,   // set false to use pure SVG checkboxes
  gap: 5,
  padding: 12,
  rowHeight: 18,
  indent: 18,
  fontSize: 12,
  cbSize: 14
};

// ---------- internals ----------
plots.toggles._stateBySvg = plots.toggles._stateBySvg ?? new WeakMap();
plots.toggles._uid = plots.toggles._uid ?? 0;
const SVGNS = "http://www.w3.org/2000/svg";
const HTMLNS = "http://www.w3.org/1999/xhtml";

// helpers
plots.toggles.cssEscape =
  (typeof CSS !== "undefined" && typeof CSS.escape === "function")
    ? CSS.escape
    : s => String(s).replace(/["\\]/g, "\\$&");

plots.toggles.getMaybeAnimatedValue = function(x) {
  if ("animVal" in x) return x.animVal.value;
  if ("baseVal" in x) return x.baseVal.value;
  return x;
}

plots.toggles.getViewBox = function(svg) {
  const vb = svg.viewBox?.baseVal;
  if (vb && vb.width > 0 && vb.height > 0) {
    return { x: vb.x, y: vb.y, width: vb.width, height: vb.height };
  }
  // fallback to screen box
  const r = svg.getBoundingClientRect();
  return { x: 0, y: 0, width: r.width, height: r.height };
};

plots.toggles.getSvgSize = function(svg) {
  return {w: plots.toggles.getMaybeAnimatedValue(svg.width),
    h: plots.toggles.getMaybeAnimatedValue(svg.height)};
}

plots.toggles.isLeaf = obj =>
  !!obj && typeof obj === "object" && Object.prototype
    .hasOwnProperty.call(obj, "id");

plots.toggles.withDefaults = function(rec) {
  const inv = (Object.prototype.hasOwnProperty.call(rec, "inverted"))
    ? rec.inverted
    : (Object.prototype.hasOwnProperty.call(rec, "invert")
        ? rec.invert : true); // support 'invert' alias
  return {
    id: rec.id,
    className: rec.className ?? "hide",
    inverted: inv,
    onClick: rec.onClick ?? null
  };
};

plots.toggles.walk = function(spec, fn, path = []) {
  if (spec === undefined || spec === null) return;
  for (const [key, val] of Object.entries(spec)) {
    const cur = path.concat(key);
    if (plots.toggles.isLeaf(val)) {
      fn({ type: "leaf", key, path: cur, record: val });
    } else if (val && typeof val === "object") {
      fn({ type: "group", key, path: cur, group: val });
      plots.toggles.walk(val, fn, cur);
    }
  }
};

plots.toggles.findNodeByPath = function(spec, path) {
  let node = spec;
  for (const k of path) {
    if (!node || typeof node !== "object") return null;
    node = node[k];
  }
  return node ?? null; // [] returns the root spec
};

plots.toggles.leafChecked = function(svg, recRaw) {
  const rec = plots.toggles.withDefaults(recRaw);
  const el = svg.querySelector('[id="' +
    plots.toggles.cssEscape(rec.id) + '"]');
  if (!el) return false;
  const has = el.classList?.contains(rec.className) ?? false;
  return rec.inverted ? !has : has;
};

plots.toggles.setLeafChecked = function(svg, recRaw, checked) {
  const rec = plots.toggles.withDefaults(recRaw);
  const el = svg.querySelector('[id="' +
    plots.toggles.cssEscape(rec.id) + '"]');
  if (!el) return;
  const shouldHave = rec.inverted ? !checked : checked;
  if (shouldHave) el.classList.add(rec.className);
  else el.classList.remove(rec.className);
};

plots.toggles.groupState = function(svg, spec, path) {
  const node = plots.toggles.findNodeByPath(spec, path);
  let any = false, all = true, hasLeaf = false;
  plots.toggles.walk(node, nd => {
    if (nd.type === "leaf") {
      hasLeaf = true;
      const ch = plots.toggles.leafChecked(svg, nd.record);
      any = any || ch;
      all = all && ch;
    }
  });
  if (!hasLeaf) return "unchecked"; // empty groups count as unchecked
  if (all) return "checked";
  if (!any) return "unchecked";
  return "mixed";
};

// ---------- rendering ----------
plots.toggles.ensurePanel = function(svg) {
  const S = plots.toggles._stateBySvg.get(svg);
  if (S.panelGroup) return;

  // defs & clip
  const defs = svg.querySelector("defs") ||
    svg.insertBefore(document.createElementNS(SVGNS, "defs"), svg.firstChild);

  const clipId = "pt-clip-" + (++plots.toggles._uid);
  const clip = document.createElementNS(SVGNS, "clipPath");
  clip.setAttribute("id", clipId);
  clip.setAttribute("clipPathUnits", "userSpaceOnUse");
  const clipRect = document.createElementNS(SVGNS, "rect");
  clip.appendChild(clipRect);
  defs.appendChild(clip);

  // root panel group (topmost)
  const g = document.createElementNS(SVGNS, "g");
  g.setAttribute("class", [S.cls.toggles, S.cls.panel, S.cls.hidden].join(" "));
  g.setAttribute("data-role", "panel");
  svg.appendChild(g);

  // background
  const bg = document.createElementNS(SVGNS, "rect");
  bg.setAttribute("class", S.cls.bg);
  g.appendChild(bg);

  // title
  const title = document.createElementNS(SVGNS, "text");
  title.setAttribute("class", S.cls.title);
  g.appendChild(title);

  // scrolling tree viewport (clipped)
  const treeViewport = document.createElementNS(SVGNS, "g");
  treeViewport.setAttribute("class", S.cls.treeViewport);
  treeViewport.setAttribute("clip-path", "url(#" + clipId + ")");
  g.appendChild(treeViewport);

  // scrolled content lives here
  const treeContent = document.createElementNS(SVGNS, "g");
  treeContent.setAttribute("class", S.cls.treeContent);
  treeViewport.appendChild(treeContent);

  Object.assign(S, {
    panelGroup: g,
    panelBg: bg,
    panelTitle: title,
    treeViewport,
    treeContent,
    clipRect,
    clipId
  });

  plots.toggles.updateLayout(svg);
  plots.toggles.rebuildTree(svg);
  plots.toggles.updateChecks(svg);
};

plots.toggles.updateLayout = function(svg) {
  const S = plots.toggles._stateBySvg.get(svg);
  const vb = plots.toggles.getViewBox(svg);
  const sz = plots.toggles.getSvgSize(svg);
  const pad = S.padding;

  // panel fills the whole current viewBox
  // S.panelBox = { x: vb.x + S.gap, y: vb.y + S.gap,
  //   w: vb.width - 2 * S.gap, h: vb.height - 2 * S.gap };
  S.panelBox = { x: 0 + S.gap, y: 0 + S.gap,
    w: sz.w - 2 * S.gap, h: sz.h - 2 * S.gap };
  S.panelGroup.setAttribute("transform",
    "translate(" + vb.x + "," + vb.y + ") " +
    "scale(" + vb.width / sz.w  + "," + vb.height / sz.h + ")");

  // bg rect
  S.panelBg.setAttribute("x", String(S.panelBox.x));
  S.panelBg.setAttribute("y", String(S.panelBox.y));
  S.panelBg.setAttribute("width", String(S.panelBox.w));
  S.panelBg.setAttribute("height", String(S.panelBox.h));

  // title position
  const titleX = S.panelBox.x + pad;
  const titleY = S.panelBox.y + pad + S.fontSize;
  S.panelTitle.setAttribute("x", String(titleX));
  S.panelTitle.setAttribute("y", String(titleY));
  S.panelTitle.textContent = S.title;

  // tree viewport rect (clip area)
  const listTop = S.panelBox.y + pad * 2 + S.fontSize;
  const listLeft = S.panelBox.x + pad;
  const listWidth = Math.max(0, S.panelBox.w - 2 * pad);
  const listHeight = Math.max(0,
    S.panelBox.h - (listTop - S.panelBox.y) - pad);

  S.clipRect.setAttribute("x", String(listLeft - pad));
  S.clipRect.setAttribute("y", String(listTop - pad));
  S.clipRect.setAttribute("width", String(listWidth + 2 * pad));
  S.clipRect.setAttribute("height", String(listHeight + 2 * pad));

  // the content group is translated; viewport remains at (0,0)
  S.treeOrigin = { x: listLeft, y: listTop, w: listWidth, h: listHeight };
  plots.toggles.updateScrollTransform(svg);
};

plots.toggles.rebuildTree = function(svg) {
  const S = plots.toggles._stateBySvg.get(svg);
  const rows = [];

  if (S.includeRoot) {
    rows.push({
      type: "group",
      key: "(all)",
      path: [],         // root path
      group: S.spec,
      depth: 0,
      isRoot: true
    });
  }

  plots.toggles.walk(S.spec, nd => {
    const depth = nd.path.length; // children start at depth 1 when root is shown
    rows.push({ ...nd, depth, isRoot: false });
  });

  S.rows = rows;

  // clear content
  while (S.treeContent.firstChild) {
    S.treeContent.removeChild(S.treeContent.firstChild);
  }

  const cbSize = S.cbSize;
  const labelDx = 6;

  rows.forEach((row, i) => {
    const gy = i * S.rowHeight;
    const gx = row.depth * S.indent;

    const gr = document.createElementNS(SVGNS, "g");
    gr.setAttribute("class", S.cls.row);
    gr.setAttribute("transform", "translate(" + gx + "," + gy + ")");
    gr.setAttribute("data-index", String(i));

    // large hit area
    const hit = document.createElementNS(SVGNS, "rect");
    hit.setAttribute("class", S.cls.rowHit);
    hit.setAttribute("x", "-4");
    hit.setAttribute("y", String(-(S.rowHeight - S.fontSize)));
    hit.setAttribute("width", String(S.treeOrigin.w - gx));
    hit.setAttribute("height", String(S.rowHeight));
    gr.appendChild(hit);

    if (S.useForeignObject) {
      const fo = document.createElementNS(SVGNS, "foreignObject");
      fo.setAttribute("width", String(cbSize));
      fo.setAttribute("height", String(cbSize));
      fo.setAttribute("y", String(-(cbSize - S.fontSize)));
      const div = document.createElementNS(HTMLNS, "div");
      const input = document.createElementNS(HTMLNS, "input");
      input.setAttribute("type", "checkbox");
      input.style.width = "100%";
      input.style.height = "100%";
      input.addEventListener("click", ev => {
        ev.stopPropagation();
        plots.toggles.onRowClick(svg, i);
      });
      div.appendChild(input);
      fo.appendChild(div);
      gr.appendChild(fo);
      // store ref for state updates
      row._checkboxEl = input;
    } else {
      // pure SVG checkbox
      const box = document.createElementNS(SVGNS, "rect");
      box.setAttribute("class", S.cls.cbBox);
      box.setAttribute("width", String(cbSize));
      box.setAttribute("height", String(cbSize));
      box.setAttribute("rx", "2");
      box.setAttribute("ry", "2");
      box.setAttribute("y", String(-(cbSize - S.fontSize)));
      gr.appendChild(box);

      const check = document.createElementNS(SVGNS, "path");
      check.setAttribute("class", S.cls.cbMark + " check");
      check.setAttribute("d", "M2,6 L5,9 L12,2");
      check.setAttribute("display", "none");
      gr.appendChild(check);

      const dash = document.createElementNS(SVGNS, "path");
      dash.setAttribute("class", S.cls.cbMark + " mixed");
      dash.setAttribute("d", "M2,5 H12");
      dash.setAttribute("display", "none");
      gr.appendChild(dash);

      row._checkMarkEl = check;
      row._dashMarkEl = dash;

      // click on box toggles
      box.addEventListener("click", ev => {
        ev.stopPropagation();
        plots.toggles.onRowClick(svg, i);
      });
    }

    const label = document.createElementNS(SVGNS, "text");
    label.setAttribute("class", S.cls.label);
    label.setAttribute("x", String(cbSize + labelDx));
    label.textContent = row.isRoot ? S.title : row.key;
    gr.appendChild(label);

    // clicking anywhere on row toggles
    gr.addEventListener("click", ev => {
      ev.stopPropagation();
      plots.toggles.onRowClick(svg, i);
    });

    S.treeContent.appendChild(gr);
  });

  // content total height
  S.contentHeight = rows.length * S.rowHeight + S.padding * 2;
  plots.toggles.updateScrollTransform(svg);
};

plots.toggles.updateScrollTransform = function(svg) {
  const S = plots.toggles._stateBySvg.get(svg);
  const y = S.treeOrigin.y - S.scrollY;
  const x = S.treeOrigin.x;
  S.treeContent.setAttribute("transform", "translate(" + x + "," + y + ")");
};

plots.toggles.updateChecks = function(svg) {
  const S = plots.toggles._stateBySvg.get(svg);
  S.rows.forEach((row) => {
    let state = "unchecked";
    if (row.type === "leaf") {
      state = plots.toggles.leafChecked(svg, row.record)
        ? "checked" : "unchecked";
    } else {
      state = plots.toggles.groupState(svg, S.spec, row.path);
    }

    if (S.useForeignObject) {
      const el = row._checkboxEl;
      if (!el) return;
      el.indeterminate = (state === "mixed");
      el.checked = (state === "checked");
    } else {
      // ensure only the right mark is visible
      if (row._checkMarkEl) row._checkMarkEl.setAttribute("display", "none");
      if (row._dashMarkEl) row._dashMarkEl.setAttribute("display", "none");
      if (state === "checked" && row._checkMarkEl) {
        row._checkMarkEl.setAttribute("display", "inline");
      } else if (state === "mixed" && row._dashMarkEl) {
        row._dashMarkEl.setAttribute("display", "inline");
      }
    }
  });
};

// ---------- interactions ----------
plots.toggles.onRowClick = function(svg, index) {
  const S = plots.toggles._stateBySvg.get(svg);
  const row = S.rows[index];
  if (!row) return;

  if (row.type === "leaf") {
    const cur = plots.toggles.leafChecked(svg, row.record);
    plots.toggles.setLeafChecked(svg, row.record, !cur);
  } else {
    const st = plots.toggles.groupState(svg, S.spec, row.path);
    const target = (st !== "checked"); // toggle groups
    const node = plots.toggles.findNodeByPath(S.spec, row.path);
    plots.toggles.walk(node, nd => {
      if (nd.type === "leaf") {
        plots.toggles.setLeafChecked(svg, nd.record, target);
      }
    });
  }
  plots.toggles.updateChecks(svg);
};

plots.toggles.attachHotkey = function(svg) {
  const S = plots.toggles._stateBySvg.get(svg);
  if (S.keyListener) return;

  svg.addEventListener("mouseenter", () => { S.hovered = true; });
  svg.addEventListener("mouseleave", () => { S.hovered = false; });

  const onKey = ev => {
    if (!S.hovered) return;
    if (ev.defaultPrevented) return;
    if (ev.key === S.hotkey) {
      ev.preventDefault();
      plots.toggles.togglePanel(svg);
    }
  };
  S.keyListener = onKey;
  window.addEventListener("keydown", onKey, { passive: false });
};

plots.toggles.attachScroll = function(svg) {
  const S = plots.toggles._stateBySvg.get(svg);
  if (S.scrollAttached) return;

  const onWheel = ev => {
    if (S.panelGroup.classList.contains(S.cls.hidden)) return;
    const within = ev.composedPath().includes(S.panelGroup);
    if (!within) return;
    ev.preventDefault();
    const maxScroll = Math.max(0, S.contentHeight - S.treeOrigin.h);
    S.scrollY = Math.max(0, Math.min(maxScroll, S.scrollY + ev.deltaY));
    plots.toggles.updateScrollTransform(svg);
  };
  S.scrollAttached = true;
  svg.addEventListener("wheel", onWheel, { passive: false });
};

plots.toggles.installOnClickHandlers = function(svg) {
  const S = plots.toggles._stateBySvg.get(svg);
  const installed = S.installedIds ?? new Set();

  plots.toggles.walk(S.spec, nd => {
    if (nd.type !== "leaf") return;
    const rec = plots.toggles.withDefaults(nd.record);
    if (!Array.isArray(rec.onClick)) return;

    const src = svg.querySelector('[id="' +
      plots.toggles.cssEscape(rec.id) + '"]');
    if (!src || installed.has(rec.id)) return;

    src.classList.add(S.cls.clickable);
    src.addEventListener("click", () => {
      const targetNode = plots.toggles.findNodeByPath(S.spec, rec.onClick);
      if (!targetNode) return;
      if (plots.toggles.isLeaf(targetNode)) {
        const cur = plots.toggles.leafChecked(svg, targetNode);
        plots.toggles.setLeafChecked(svg, targetNode, !cur);
      } else {
        const st = plots.toggles.groupState(svg, S.spec, rec.onClick);
        const want = (st !== "checked");
        plots.toggles.walk(targetNode, n2 => {
          if (n2.type === "leaf") {
            plots.toggles.setLeafChecked(svg, n2.record, want);
          }
        });
      }
      plots.toggles.updateChecks(svg);
    });

    installed.add(rec.id);
  });

  S.installedIds = installed;
};

// open/close and layout sync
plots.toggles.openPanel = function(svg) {
  plots.toggles.updateLayout(svg); // ensure it fills current viewBox
  const S = plots.toggles._stateBySvg.get(svg);
  S.panelGroup.classList.remove(S.cls.hidden);
  plots.toggles.updateChecks(svg);
};

plots.toggles.closePanel = function(svg) {
  const S = plots.toggles._stateBySvg.get(svg);
  if (!S || !S.panelGroup) return;
  S.panelGroup.classList.add(S.cls.hidden);
};

plots.toggles.togglePanel = function(svg) {
  const S = plots.toggles._stateBySvg.get(svg);
  if (!S.panelGroup || S.panelGroup.classList.contains(S.cls.hidden)) {
    plots.toggles.openPanel(svg);
  } else {
    plots.toggles.closePanel(svg);
  }
};

// ---------- public API ----------
plots.toggles.attach = function(svg, spec = plots.toggles.spec, opts = {}) {
  const cls = plots.toggles.classes;
  const cfg = plots.toggles.defaults;

  const S = {
    spec,
    cls,
    title: opts.title ?? cfg.title,
    hotkey: opts.hotkey ?? cfg.hotkey,
    includeRoot: (opts.includeRoot ?? cfg.includeRoot),
    useForeignObject: (opts.useForeignObject ?? cfg.useForeignObject),
    padding: opts.padding ?? cfg.padding,
    gap: opts.gap ?? cfg.gap,
    rowHeight: opts.rowHeight ?? cfg.rowHeight,
    indent: opts.indent ?? cfg.indent,
    fontSize: opts.fontSize ?? cfg.fontSize,
    cbSize: opts.cbSize ?? cfg.cbSize,
    hovered: false,
    scrollY: 0
  };
  plots.toggles._stateBySvg.set(svg, S);

  plots.toggles.ensurePanel(svg);
  plots.toggles.attachHotkey(svg);
  plots.toggles.attachScroll(svg);
  plots.toggles.installOnClickHandlers(svg);

  // observe viewBox changes to keep panel full-bleed to current view
  const mo = new MutationObserver(muts => {
    for (const m of muts) {
      if (m.attributeName === "viewBox") {
        plots.toggles.updateLayout(svg);
      }
    }
  });
  mo.observe(svg, { attributes: true, attributeFilter: ["viewBox"] });
  S._mo = mo;
};

// Auto-attach when inline in <svg>
if (document.currentScript && document.currentScript.ownerSVGElement) {
  // const __svg = document.currentScript.ownerSVGElement;
  const __svg = document.documentElement;
  plots.toggles.attach(__svg, plots.toggles.spec);
}
